13	type EnvironmentEditorProps = {
14	  diskName: string;
15	  environmentName?: string;
16	  environmentNamesSelected: string[];
17	  id: number;
18	  kind?: EnvironmentKind;
19	  namespace: string;
20	  onChange: (diskName: string, name: string, serial: string, kind: EnvironmentKind) => void;
