36	  const { t } = useKubevirtTranslation();
37	
38	  return (
39	    <div className="row pairs-list__row">
40	      <div className="col-xs-5 pairs-list__value-pair-field">
41	        <EnvironmentSelectResource
42	          diskName={diskName}
43	          environmentName={environmentName}
44	          environmentNamesSelected={environmentNamesSelected}
45	          kind={kind}
46	          namespace={namespace}
47	          onChange={onChange}
48	          serial={serial}
49	        />
50	      </div>
51	
52	      <div className="col-xs-5 pairs-list__name-field">
53	        <TextInput
54	          aria-labelledby="environment-serial-header"
55	          id={`${id}-serial`}
56	          onChange={(_, value) => onChange(diskName, environmentName, value, kind)}
57	          type="text"
58	          value={serial}
59	        />
60	      </div>
61	      <div className="col-xs-1 pairs-list__action">
62	        <Tooltip content={t('Remove')}>
63	          <Button
64	            className="pairs-list__span-btns"
65	            data-test-id="pairs-list__delete-from-btn"
66	            onClick={() => onRemove(diskName)}
67	            type="button"
68	            variant="plain"
69	          >
70	            <MinusCircleIcon className="pairs-list__side-btn pairs-list__delete-icon" />
71	            <span className="sr-only">{t('Delete')}</span>
72	          </Button>
73	        </Tooltip>
74	      </div>
75	    </div>
76	  );
77	};
78	export default EnvironmentEditor;

